// Modèle
public class Produit {
    public int Id { get; set; }
    public string Nom { get; set; }
    public decimal Prix { get; set; }
    public int Stock { get; set; }
}

// DbContext
public class AppDbContext : DbContext {
    public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }
    public DbSet<Produit> Produits { get; set; }
}

// Contrôleur
[ApiController]
[Route("api/[controller]")]
public class ProduitsController : ControllerBase {
    private readonly AppDbContext _context;
    public ProduitsController(AppDbContext context) => _context = context;

    [HttpGet]
    public async Task<IActionResult> Get() => Ok(await _context.Produits.ToListAsync());

    [HttpPost]
    [Authorize(Roles = "Admin")]
    public async Task<IActionResult> Post([FromBody] Produit produit) {
        if (!ModelState.IsValid) return BadRequest();
        _context.Produits.Add(produit);
        await _context.SaveChangesAsync();
        return CreatedAtAction(nameof(Get), new { id = produit.Id }, produit);
    }
}

